defmodule MyAppWeb.UserController do
  use Phoenix.Controller
  
  alias Ecto.Changeset
  import Plug.Conn
    
  plug :fetch_session when not in [:dev] # for production, you should handle this with a real session manager like Guardian or Absinthe's JWT implementation
      
  def update(conn, %{"id" => id} = params) do  
    user =  MyApp.Repo.get_user(String.to_integer(id)) # assuming the repo has a get/1 method for getting by ID    
        
    changeset  = User.changeset(user, params["data"] || %{}) 
                |> Changeset.apply_action(:update)  
                        
    case MyApp.Repo.insert(changeset) do     
        {:ok, user} ->  # on successful update or creation of a new resource        
            conn          
            |> put_flash :info ,"User updated successfully"         
            |> redirect(to: Routes.user_path(conn, :show, id))  
        {:error, changeset} ->  # on update or creation failure    
            render("edit.html", conn: conn, user: user ,changeset: changeset)     
    end         
  end      
end